// ============================================================
//  contact.js  —  WellSpring Family Clinic | Contact Page
//  ICT502 – Internet and Web Development | Assessment 2
//
//  HOW TO SET UP EMAILJS (free):
//  1. Go to https://www.emailjs.com and create a free account
//  2. Add an Email Service (Gmail, Outlook, etc.) → copy Service ID
//  3. Create an Email Template → copy Template ID
//  4. Go to Account > API Keys → copy your Public Key
//  5. Replace the three placeholders below with your real values
// ============================================================

const EMAILJS_PUBLIC_KEY  = 'YOUR_PUBLIC_KEY';   // ← paste here
const EMAILJS_SERVICE_ID  = 'YOUR_SERVICE_ID';   // ← paste here
const EMAILJS_TEMPLATE_ID = 'template_contact';  // ← paste here



// ── Utility helpers ────────────────────────────────────────

function setContactError(id, msg) {
  const el = document.getElementById(id);
  if (el) {
    el.textContent   = msg;
    el.style.display = 'block';
  }
}

function clearContactErrors() {
  document.querySelectorAll('.form-error').forEach(el => {
    el.textContent   = '';
    el.style.display = 'none';
  });
  ['contact-success', 'contact-fail'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = 'none';
  });
}

function isValidEmail(v) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

// ── Form submission ────────────────────────────────────────

document.addEventListener('DOMContentLoaded', () => {

  // Initialise EmailJS once the page loads
  emailjs.init(EMAILJS_PUBLIC_KEY);

  const form = document.getElementById('contact-form');
  if (!form) return;

  form.addEventListener('submit', function (e) {
    e.preventDefault();
    clearContactErrors();

    // Read field values
    const name    = document.getElementById('contact-name').value.trim();
    const email   = document.getElementById('contact-email').value.trim();
    const subject = document.getElementById('contact-subject').value;
    const message = document.getElementById('contact-message').value.trim();

    // ── Validation ──
    let isValid = true;

    if (!name) {
      setContactError('contact-name-error', 'Your name is required.');
      isValid = false;
    }
    if (!email || !isValidEmail(email)) {
      setContactError('contact-email-error', 'Please enter a valid email address.');
      isValid = false;
    }
    if (!subject) {
      setContactError('contact-subject-error', 'Please select a subject.');
      isValid = false;
    }
    if (!message || message.length < 10) {
      setContactError('contact-message-error', 'Message must be at least 10 characters.');
      isValid = false;
    }

    if (!isValid) return;

    // ── Send via EmailJS ──
    const btn = document.getElementById('contact-submit');
    btn.disabled    = true;
    btn.textContent = 'Sending…';

    emailjs.sendForm(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, form)
      .then(() => {
        const successEl = document.getElementById('contact-success');
        successEl.textContent  = "✅ Thank you! Your message has been sent. We'll reply within 1 business day.";
        successEl.style.display = 'block';

        form.reset();
        btn.disabled    = false;
        btn.textContent = 'Send Message';
        window.scrollTo({ top: 0, behavior: 'smooth' });
      })
      .catch((error) => {
        console.error('EmailJS error:', error);
        const failEl = document.getElementById('contact-fail');
        failEl.textContent  = '❌ Something went wrong. Please email us at info@wellspringclinic.com.au';
        failEl.style.display = 'block';

        btn.disabled    = false;
        btn.textContent = 'Send Message';
      });
  });
});
